# @cctt_verify {"v":2,"sym":"sympy.assumptions.handlers.common._","kind":"function","src_hash":"377a47088732efef","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"_(exp)","rhs":"objects are expected to be commutative unless otherwise stated","over":{"base":"Any"},"name":"__correct"},"guarantee":"objects are expected to be commutative unless otherwise stated","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.assumptions.handlers.common.__correct","statement":"Path(_(x), objects are expected to be commutative unless otherwise stated)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"dd69a834c86a2e63"}
def _(expr, assumptions):
    """Objects are expected to be commutative unless otherwise stated"""
    assumps = conjuncts(assumptions)
    if expr.is_commutative is not None:
        return expr.is_commutative and not ~Q.commutative(expr) in assumps
    if Q.commutative(expr) in assumps:
        return True
    elif ~Q.commutative(expr) in assumps:
        return False
    return True

